module RefModule(
    input [7:0] A,
    input [7:0] B,
    input add,
    input sub,
    output [7:0] Z
);reg [7:0] final_sig;

    always @(*) begin
        if (add) begin
            final_sig = A + B;
        end
        else if (sub) begin
            final_sig = A - B;
        end
        else begin
            final_sig = 8'b0;
        end
    end

    assign Z = final_sig;

endmodule
